class DSU {
  constructor(n) {
    this.parent = Array(n + 1).fill(0).map((_, i) => i);
    this.rank = Array(n + 1).fill(1);
  }

  find(x) {
    if (this.parent[x] !== x) {
      this.parent[x] = this.find(this.parent[x]);
    }
    return this.parent[x];
  }

  union(x, y) {
    const xroot = this.find(x);
    const yroot = this.find(y);
    if (xroot === yroot) return;
    if (this.rank[xroot] < this.rank[yroot]) {
      this.parent[xroot] = yroot;
    } else {
      this.parent[yroot] = xroot;
      if (this.rank[xroot] === this.rank[yroot]) {
        this.rank[xroot]++;
      }
    }
  }
}

function solve(c, connections, queries) {
  const dsu = new DSU(c);
  for (const [u, v] of connections) {
    dsu.union(u, v);
  }

  const groups = new Map();
  for (let i = 1; i <= c; i++) {
    const root = dsu.find(i);
    if (!groups.has(root)) {
      groups.set(root, []);
    }
    groups.get(root).push(i);
  }

  for (const group of groups.values()) {
    group.sort((a, b) => a - b);
  }

  const componentMin = new Map();
  for (const [root, group] of groups.entries()) {
    componentMin.set(root, group[0]);
  }

  const isOnline = Array(c + 1).fill(true);

  const result = [];

  for (const [type, x] of queries) {
    if (type === 1) {
      if (isOnline[x]) {
        result.push(x);
      } else {
        const root = dsu.find(x);
        const currentMin = componentMin.get(root);
        if (currentMin !== undefined) {
          result.push(currentMin);
        } else {
          result.push(-1);
        }
      }
    } else {
      isOnline[x] = false;
      const root = dsu.find(x);
      const currentMin = componentMin.get(root);
      if (currentMin === x) {
        const group = groups.get(root);
        let newMin = null;
        for (const station of group) {
          if (isOnline[station]) {
            newMin = station;
            break;
          }
        }
        componentMin.set(root, newMin);
      }
    }
  }

  return result;
}
